local _M = {}

-- Secret key for token validation (in production, use a secure configuration)
local AUTH_SECRET = "your_secret_key_here"
local cjson = require "cjson.safe"
local ngx = ngx

-- Define role hierarchy and permissions
local role_permissions = {
    admin = {
        "/admin/dashboard",
        "/admin/users",
        "/admin/settings",
        "/api/v1/users",
        "/api/v1/reports",
        "/api/v1/config",
        "/api/v1/data"
    },
    editor = {
        "/api/v1/data",
        "/api/v1/reports",
        "/api/v1/content"
    },
    viewer = {
        "/api/v1/data",
        "/api/v1/reports"
    }
}

-- Endpoints that skip permission checks (public endpoints)
local public_endpoints = {
    "/health",
    "/status",
    "/login",
    "/register",
    "/public"
}

-- Helper: check if a URI matches any pattern in a list
local function uri_matches_any(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Helper: decode a base64url string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Helper: validate and decode JWT-like token
local function decode_token(token)
    if not token or token == "" then
        return nil, "empty token"
    end

    -- Split token into parts (header.payload.signature)
    local parts = {}
    for part in string.gmatch(token, "([^%.]+)") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "invalid token format"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local expected_signature = ngx.encode_base64(ngx.hmac_sha1(AUTH_SECRET, signing_input))
    -- Normalize base64url
    expected_signature = expected_signature:gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature ~= expected_signature then
        return nil, "invalid signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "failed to decode payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "failed to parse payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    local current_time = ngx.time()
    if payload.exp and payload.exp < current_time then
        return nil, "token expired"
    end

    -- Check issued at time (not from the future)
    if payload.iat and payload.iat > current_time + 60 then
        return nil, "token issued in the future"
    end

    return payload, nil
end

-- Helper: check if a user role has permission for a given URI
local function check_role_permission(role, uri)
    if not role or not role_permissions[role] then
        return false
    end

    local allowed_paths = role_permissions[role]
    for _, allowed_path in ipairs(allowed_paths) do
        -- Use string matching to check if the URI starts with or contains the allowed path
        if string.find(uri, "^" .. allowed_path) or string.find(uri, allowed_path, 1, true) then
            return true
        end
    end

    return false
end

-- Helper: extract token from Authorization header
local function extract_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil, "missing Authorization header"
    end

    -- Match Bearer token pattern
    local token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
    if not token then
        return nil, "invalid Authorization header format, expected 'Bearer <token>'"
    end

    return token, nil
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri
    local request_method = ngx.req.get_method()

    -- Log the incoming request
    ngx.log(ngx.INFO, "Access check for URI: ", uri, " Method: ", request_method)

    -- Step 1: Check if the endpoint is public (skip permission checks)
    if uri_matches_any(uri, public_endpoints) then
        ngx.log(ngx.INFO, "Public endpoint accessed: ", uri, " - skipping permission check")
        return true
    end

    -- Step 2: Check if the URI contains "/admin" or "/api" - these require authentication
    local requires_auth = false
    if string.find(uri, "/admin", 1, true) then
        requires_auth = true
        ngx.log(ngx.INFO, "Admin endpoint detected: ", uri)
    elseif string.find(uri, "/api", 1, true) then
        requires_auth = true
        ngx.log(ngx.INFO, "API endpoint detected: ", uri)
    end

    -- If the URI doesn't match /admin or /api patterns, skip permission checks
    if not requires_auth then
        ngx.log(ngx.INFO, "Non-protected endpoint: ", uri, " - skipping permission check")
        return true
    end

    -- Step 3: Extract and validate authentication token
    local token, err = extract_token()
    if not token then
        ngx.log(ngx.WARN, "Authentication failed for ", uri, ": ", err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = err
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    local payload, decode_err = decode_token(token)
    if not payload then
        ngx.log(ngx.WARN, "Token validation failed for ", uri, ": ", decode_err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access", error="invalid_token"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Invalid token: " .. decode_err
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Extract user information from token payload
    local user_id = payload.sub or payload.user_id
    local user_role = payload.role
    local username = payload.username or "unknown"

    if not user_id then
        ngx.log(ngx.WARN, "Token missing user identifier for ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Token missing user identifier"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    if not user_role then
        ngx.log(ngx.WARN, "Token missing role for user: ", username)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "forbidden",
            message = "No role assigned to user"
        }))
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Step 5: Check if user role has permission for the requested URI
    -- Admin endpoints require admin role specifically
    if string.find(uri, "/admin", 1, true) then
        if not string.match(user_role, "^admin$") then
            ngx.log(ngx.WARN, "Non-admin user '", username, "' (role: ", user_role,
                ") attempted to access admin endpoint: ", uri)
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = "forbidden",
                message = "Admin access required"
            }))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end

    -- Check role-based permissions for the specific URI
    if not check_role_permission(user_role, uri) then
        ngx.log(ngx.WARN, "Permission denied for user '", username, "' (role: ", user_role,
            ") accessing: ", uri)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "forbidden",
            message = "Insufficient permissions for this resource"
        }))
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Step 6: Set upstream headers with user info for downstream services
    ngx.req.set_header("X-User-ID", user_id)
    ngx.req.set_header("X-User-Role", user_role)
    ngx.req.set_header("X-Username", username)

    ngx.log(ngx.INFO, "Access granted for user '", username, "' (role: ", user_role,
        ") to: ", uri)

    -- Store user info in ngx.ctx for potential use in later phases
    ngx.ctx.user = {
        id = user_id,
        role = user_role,
        username = username
    }

    return true
end

-- Rate limiting helper per user (optional enhancement)
function _M.check_rate_limit()
    if not ngx.ctx.user then
        return true
    end

    local user_id = ngx.ctx.user.id
    local limit_dict = ngx.shared.rate_limit

    if not limit_dict then
        ngx.log(ngx.WARN, "rate_limit shared dict not configured, skipping rate limit")
        return true
    end

    local key = "rate:" .. user_id
    local count, err = limit_dict:incr(key, 1, 0, 60) -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "Rate limit incr error: ", err)
        return true
    end

    -- Define rate limits per role
    local rate_limits = {
        admin = 1000,
        editor = 500,
        viewer = 200
    }

    local role = ngx.ctx.user.role
    local max_requests = rate_limits[role] or 100

    if count > max_requests then
        ngx.log(ngx.WARN, "Rate limit exceeded for user: ", user_id, " (", count, "/", max_requests, ")")
        ngx.status = 429
        ngx.header["Content-Type"] = "application/json"
        ngx.header["Retry-After"] = "60"
        ngx.say(cjson.encode({
            error = "too_many_requests",
            message = "Rate limit exceeded. Please try again later.",
            retry_after = 60
        }))
        return ngx.exit(429)
    end

    return true
end

-- Entry point: run all access checks
function _M.run()
    local ok = _M.check_access()
    if ok then
        _M.check_rate_limit()
    end
end

return _M